/**
 * StressEnergyMonitor.ts -- formal thermodynamic stability for real-time systems.
 * Grounded in StressEnergyTensor.lean and TuringMachineHalting.lean.
 */

export interface StressEnergyState {
  cpuUsage: number;         // T_00 (Energy density)
  latencyMs: number;        // T_0i (Momentum / Flux)
  throughput: number;       // T_ij (Stress / Pressure)
  structuralIntegrity: number; // The "Metric" (g_uv)
}

/**
 * THM-THERMODYNAMIC-STABILITY:
 * A system is stable only if the trace of its Stress-Energy tensor (T)
 * remains within the bounds of its structural metric (g).
 * If T > g, the system is entering a "Singularity" (Collapse/Market Crash).
 */
export class StressEnergyMonitor {
  private stabilityCeiling: number; // The "R" of the physical system

  constructor(ceiling: number = 1.0) {
    this.stabilityCeiling = ceiling;
  }

  /**
   * Calculates the current structural Stress (T).
   * Aggregates CPU, Latency, and Throughput into a normalized vector.
   */
  public calculateStress(state: StressEnergyState): number {
    const energyDensity = state.cpuUsage / 100;
    const flux = Math.min(1.0, state.latencyMs / 500); // Latency flux
    const pressure = Math.min(1.0, state.throughput / 10000); // RPS/Throughput pressure
    
    // T = sqrt(T00^2 + sum(T0i^2) + sum(Tij^2))
    return Math.sqrt(
      Math.pow(energyDensity, 2) + 
      Math.pow(flux, 2) + 
      Math.pow(pressure, 2)
    );
  }

  /**
   * THM-THERMODYNAMIC-HALT:
   * Triggers a "Safety Brake" (Slam) when the Stress (T) exceeds 
   * the local Integrity (g).
   */
  public shouldHalt(state: StressEnergyState): { halt: boolean; risk: number } {
    const stress = this.calculateStress(state);
    const integrity = state.structuralIntegrity;
    
    const risk = stress / Math.max(0.001, integrity);
    return { 
      halt: risk > this.stabilityCeiling, 
      risk 
    };
  }

  /**
   * Calculates the "Bule Temperature" of the hardware state.
   */
  public getHardwareBule(state: StressEnergyState): number {
    return this.calculateStress(state) * 100;
  }
}
